import React from "react";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useController } from "react-hook-form";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";

export const BooleanField: React.FC<AutoFormFieldProps> = ({
  id,
  label,
  inputProps,
  parsedField,
}) => {
  const { field } = useController({ name: id });

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      e.preventDefault();
      (
        document.querySelector('button[type="submit"]') as HTMLButtonElement
      )?.click();
    }
  };

  return (
    <div className="flex items-center gap-2">
      <Checkbox
        id={id}
        {...inputProps}
        {...field}
        checked={!!field.value}
        onCheckedChange={field.onChange}
        onKeyDown={handleKeyDown}
      />
      <Label htmlFor={id}>
        {label}
        {parsedField.required && <span className="text-destructive"> *</span>}
      </Label>
    </div>
  );
};

import React from "react";
import { CalendarIcon } from "lucide-react";
import { useController } from "react-hook-form";

import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Input } from "@/components/ui/input";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import type { AutoFormFieldProps } from "@dual-autoform/react";

function formatDate(date: Date | undefined) {
  if (!date) return "";
  return date.toLocaleDateString("en-CA");
}

function isValidDate(date: Date | undefined) {
  return !!date && !isNaN(date.getTime());
}

function toDate(value: unknown) {
  if (value instanceof Date) return isValidDate(value) ? value : undefined;
  if (typeof value === "string" && value) {
    const date = new Date(value);
    return isValidDate(date) ? date : undefined;
  }
  return undefined;
}

const nativeDateInputStyles = `
  input[data-autoform-date]::-webkit-calendar-picker-indicator,
  input[data-autoform-date]::-webkit-inner-spin-button,
  input[data-autoform-date]::-webkit-clear-button {
    display: none !important;
    -webkit-appearance: none !important;
    width: 0 !important;
    margin: 0 !important;
    opacity: 0 !important;
    pointer-events: none !important;
  }
`;

export const DateField: React.FC<AutoFormFieldProps> = ({
  inputProps,
  error,
  id,
}) => {
  const { field } = useController({ name: id });
  const { value, onChange, ref, ...restField } = field;
  const selectedDate = toDate(value);
  const [open, setOpen] = React.useState(false);
  const [month, setMonth] = React.useState<Date | undefined>(selectedDate);
  const [inputValue, setInputValue] = React.useState(formatDate(selectedDate));

  React.useEffect(() => {
    setInputValue(formatDate(selectedDate));
    setMonth(selectedDate);
  }, [selectedDate?.getTime()]);

  return (
    <>
      <style>{nativeDateInputStyles}</style>
      <div className="relative">
        <Input
          id={id}
          {...inputProps}
          {...restField}
          ref={ref}
          type="date"
          data-autoform-date
          className={`${error ? "border-destructive " : ""}pr-10 appearance-none ${
            inputProps?.className ?? ""
          }`}
          value={inputValue}
          placeholder={inputProps?.placeholder ?? "2025-06-01"}
          onBlur={(e) => {
            restField.onBlur();
            inputProps?.onBlur?.(e);
          }}
          onChange={(e) => {
            const nextValue = e.target.value;
            const nextDate = new Date(nextValue);

            setInputValue(nextValue);

            if (isValidDate(nextDate)) {
              onChange(formatDate(nextDate));
              setMonth(nextDate);
            } else if (!nextValue) {
              onChange("");
            }
          }}
          onKeyDown={(e) => {
            inputProps?.onKeyDown?.(e);

            if (e.defaultPrevented) return;

            if (e.key === "ArrowDown") {
              e.preventDefault();
              setOpen(true);
            }
          }}
        />
        <Popover open={open} onOpenChange={setOpen}>
          <PopoverTrigger asChild>
            <Button
              id={`${id}-date-picker`}
              type="button"
              variant="ghost"
              size="icon"
              className="absolute top-1/2 size-8 text-muted-foreground"
              style={{ right: "0.25rem", transform: "translateY(-50%)" }}
              aria-label="Select date"
            >
              <CalendarIcon className="size-4" />
              <span className="sr-only">Select date</span>
            </Button>
          </PopoverTrigger>
          <PopoverContent
            className="w-auto overflow-hidden p-0"
            align="end"
            alignOffset={-8}
            sideOffset={10}
          >
            <Calendar
              mode="single"
              captionLayout="dropdown"
              selected={selectedDate}
              month={month}
              onMonthChange={setMonth}
              onSelect={(date) => {
                onChange(formatDate(date));
                setInputValue(formatDate(date));
                setMonth(date);
                setOpen(false);
              }}
            />
          </PopoverContent>
        </Popover>
      </div>
    </>
  );
};

import { Input } from "@/components/ui/input";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useController } from "react-hook-form";
